// Get funds from users
// Withdraw funds
// Set a minimum funding value in USD

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;
import {AggregatorV3Interface} from "@chainlink/contracts/src/v0.8/shared/interfaces/AggregatorV3Interface.sol";

contract FundMe{
        AggregatorV3Interface internal dataFeed;

    uint256 public  minimumUSD = 50 * 1e18 ;
    function fund() public payable  {
        // Want to be able to set a minimu fund amount in USD
        // 1. How do we send ETH to this contract?
        require(msg.value >= minimumUSD, "Didn't send enough"); // Should send more than or equal 1 ether
    }

    function getPrice() public view returns(uint256) {
        // ABI
        // Address 0x694AA1769357215DE4FAC081bf1f309aDC325306 (get from the chainlink price feed)
        AggregatorV3Interface priceFeed  = AggregatorV3Interface(0x694AA1769357215DE4FAC081bf1f309aDC325306);
        (,int price,,,) = priceFeed.latestRoundData();
        return uint256(price * 1e10);
    }

    function getConversionRate(uint256 ethAmount) public  view returns(uint256) {
        uint256 price = getPrice();
        uint256 ethToUsd = (price * ethAmount) / 1e18;
        return ethToUsd;
    }



    // function withdraw(){}
}

